// Enhanced Navbar with dark mode toggle, notifications bell, and currency selector
import React, { useState, useEffect, useRef } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuthStore } from '../stores/authStore';
import useDarkMode from '../hooks/useDarkMode';
import useCurrency, { CURRENCIES } from '../hooks/useCurrency';
import { notificationService } from '../services/api';
import './Navbar.css';

const Navbar = () => {
  const { user, logout } = useAuthStore();
  const { isDark, toggle: toggleDark } = useDarkMode();
  const { currency, setCurrency } = useCurrency();
  const navigate = useNavigate();
  const location = useLocation();

  const [unreadCount, setUnreadCount]         = useState(0);
  const [showUserMenu, setShowUserMenu]       = useState(false);
  const [showCurrencyMenu, setShowCurrencyMenu] = useState(false);
  const [mobileOpen, setMobileOpen]           = useState(false);

  const userMenuRef     = useRef(null);
  const currencyMenuRef = useRef(null);

  // Fetch unread notifications
  useEffect(() => {
    const load = async () => {
      try {
        const res = await notificationService.getUnread();
        setUnreadCount(Array.isArray(res.data) ? res.data.length : 0);
      } catch { setUnreadCount(0); }
    };
    load();
    const interval = setInterval(load, 60000);
    return () => clearInterval(interval);
  }, []);

  // Close menus on outside click
  useEffect(() => {
    const handler = (e) => {
      if (userMenuRef.current && !userMenuRef.current.contains(e.target)) setShowUserMenu(false);
      if (currencyMenuRef.current && !currencyMenuRef.current.contains(e.target)) setShowCurrencyMenu(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // Close mobile menu on route change
  useEffect(() => { setMobileOpen(false); }, [location]);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const navLinks = [
    { path: '/dashboard',  label: 'Dashboard',  icon: '­¤ōŖ' },
    { path: '/expenses',   label: 'Expenses',    icon: '­¤ÆĖ' },
    { path: '/budget',     label: 'Budget',      icon: '­¤Ä»' },
    { path: '/insights',   label: 'Insights',    icon: '­¤ż¢' },
    { path: '/recurring',  label: 'Recurring',   icon: '­¤öü' },
    { path: '/reports',    label: 'Reports',     icon: '­¤ōä' },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="navbar">
      <div className="navbar-inner">
        {/* Logo */}
        <Link to="/dashboard" className="navbar-brand">
          <span className="brand-icon">­¤Æ░</span>
          <span className="brand-text">FinTracker</span>
        </Link>

        {/* Desktop nav links */}
        <div className="navbar-links">
          {navLinks.map(({ path, label, icon }) => (
            <Link
              key={path}
              to={path}
              className={`nav-link ${isActive(path) ? 'active' : ''}`}
            >
              <span className="nav-icon">{icon}</span>
              <span>{label}</span>
            </Link>
          ))}
        </div>

        {/* Right side controls */}
        <div className="navbar-actions">
          {/* Dark mode toggle */}
          <button
            className="action-btn"
            onClick={toggleDark}
            title={isDark ? 'Switch to Light Mode' : 'Switch to Dark Mode'}
          >
            {isDark ? 'ŌśĆ’ĖÅ' : '­¤īÖ'}
          </button>

          {/* Currency selector */}
          <div className="dropdown-wrap" ref={currencyMenuRef}>
            <button
              className="action-btn currency-btn"
              onClick={() => setShowCurrencyMenu(p => !p)}
              title="Change currency"
            >
              {currency}
            </button>
            {showCurrencyMenu && (
              <div className="dropdown-menu currency-menu">
                {CURRENCIES.map(c => (
                  <button
                    key={c.code}
                    className={`dropdown-item ${currency === c.code ? 'active' : ''}`}
                    onClick={() => { setCurrency(c.code); setShowCurrencyMenu(false); }}
                  >
                    <span className="currency-symbol">{c.symbol}</span>
                    <span>{c.name}</span>
                    {currency === c.code && <span className="check">Ō£ō</span>}
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Notifications */}
          <Link to="/notifications" className="action-btn notification-btn" title="Notifications">
            ­¤öö
            {unreadCount > 0 && (
              <span className="notif-badge">{unreadCount > 9 ? '9+' : unreadCount}</span>
            )}
          </Link>

          {/* User avatar menu */}
          <div className="dropdown-wrap" ref={userMenuRef}>
            <button
              className="user-avatar-btn"
              onClick={() => setShowUserMenu(p => !p)}
            >
              <div className="avatar">
                {user?.firstName?.[0]?.toUpperCase() || user?.username?.[0]?.toUpperCase() || 'U'}
              </div>
              <span className="user-name">{user?.firstName || user?.username}</span>
              <span className="chevron">Ō¢Š</span>
            </button>
            {showUserMenu && (
              <div className="dropdown-menu user-menu">
                <div className="user-menu-header">
                  <div className="avatar avatar-lg">
                    {user?.firstName?.[0]?.toUpperCase() || 'U'}
                  </div>
                  <div>
                    <div className="user-full-name">
                      {user?.firstName} {user?.lastName}
                    </div>
                    <div className="user-email">{user?.email}</div>
                  </div>
                </div>
                <hr className="menu-divider" />
                <Link to="/profile" className="dropdown-item" onClick={() => setShowUserMenu(false)}>
                  ­¤æż Profile Settings
                </Link>
                <Link to="/reports" className="dropdown-item" onClick={() => setShowUserMenu(false)}>
                  ­¤ōä Reports
                </Link>
                <hr className="menu-divider" />
                <button className="dropdown-item danger" onClick={handleLogout}>
                  ­¤Ü¬ Sign Out
                </button>
              </div>
            )}
          </div>

          {/* Mobile hamburger */}
          <button
            className="hamburger"
            onClick={() => setMobileOpen(p => !p)}
            aria-label="Toggle menu"
          >
            {mobileOpen ? 'Ō£Ģ' : 'Ōś░'}
          </button>
        </div>
      </div>

      {/* Mobile menu */}
      {mobileOpen && (
        <div className="mobile-menu">
          {navLinks.map(({ path, label, icon }) => (
            <Link
              key={path}
              to={path}
              className={`mobile-nav-link ${isActive(path) ? 'active' : ''}`}
            >
              <span>{icon}</span> {label}
            </Link>
          ))}
          <button className="mobile-nav-link danger" onClick={handleLogout}>
            ­¤Ü¬ Sign Out
          </button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
